#include<bits/stdc++.h>
using namespace std;
long long b[500010];
struct segment_tree
{
    struct node
    {
        long long l,r,len,sum,lmax,rmax,max1;
        long long lson,rson;
        long long tag;
        node():tag(0){}
    }a[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        long long ls=a[x].lson,rs=a[x].rson;
        a[x].sum=a[ls].sum+a[rs].sum;
        if(a[ls].lmax==a[ls].len)
        {
            a[x].lmax=a[ls].len+a[rs].lmax;
        }
        else
        {
            a[x].lmax=a[ls].lmax;
        }
        if(a[rs].rmax==a[rs].len)
        {
            a[x].rmax=a[rs].len+a[ls].rmax;
        }
        else
        {
            a[x].rmax=a[rs].rmax;
        }
        a[x].max1=max({a[ls].max1,a[rs].max1,a[ls].rmax+a[rs].lmax});
    }
    void push(int x,int val)
    {
        if(val==1)
        {
            a[x].max1=a[x].lmax=a[x].rmax=a[x].len;
            a[x].sum=0;
            a[x].tag=1;
        }
        else
        {
            a[x].max1=a[x].lmax=a[x].rmax=0;
            a[x].sum=a[x].len;
            a[x].tag=2;
        }
    }
    void pushdown(long long x)
    {
        long long ls=a[x].lson,rs=a[x].rson;
        long long tg=a[x].tag;
        if(!tg)
        {
            return;
        }
        push(ls,tg);
        push(rs,tg);
        a[x].tag=0;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        a[x].tag=0;
        a[x].len=r-l+1;
        if(l==r)
        {
            a[x].sum=1;
            a[x].lmax=a[x].rmax=a[x].max1=0;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            push(x,z);
            return;
        }
        pushdown(x);
        update(a[x].lson,l,r,z);
        update(a[x].rson,l,r,z);
        pushup(x);
    }
    long long getsum(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        return (getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r));
    }
    long long getans(long long x,long long l,long long r)
    {
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].max1;
        }
        long long mid=(a[x].l+a[x].r)>>1;
        pushdown(x);
        if(l<=mid&&r>mid)
        {
            return max({getans(a[x].lson,l,r),getans(a[x].rson,l,r),min(a[a[x].lson].rmax,a[a[x].rson].l-l)+min(a[a[x].rson].lmax,r-a[a[x].lson].r)});
        }
        else if(l<=mid)
        {
            return getans(a[x].lson,l,r);
        }
        else
        {
            return getans(a[x].rson,l,r);
        }
    }
}t;
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    t.init(1,n);
    while(m--)
    {
        long long op,x,y;
        scanf("%lld%lld%lld",&op,&x,&y);
        if(op==0)
        {
            t.update(1,x,y,1);
        }
        else if(op==1)
        {
            long long l,r;
            scanf("%lld%lld",&l,&r);
            long long tmp=t.getsum(1,x,y);
            if(tmp==0)
            {
                continue;
            }
            t.update(1,x,y,1);
            int L=l,R=r+1;
            while(L+1<R)
            {
                int mid=(L+R)>>1;
                if((mid-l+1-t.getsum(1,l,mid))<=tmp)
                {
                    L=mid;
                }
                else
                {
                    R=mid;
                }
            }
            t.update(1,l,L,2);
        }
        else
        {
            printf("%lld\n",t.getans(1,x,y));
        }
    }
    return 0;
}
